                    <p><strong>Data/Hora:</strong> ${estadoAgendamento.data_hora_display}</p>
                    <p><strong>Nome:</strong> ${estadoAgendamento.cliente_nome}</p>
                    <p><strong>Telefone:</strong> ${estadoAgendamento.cliente_telefone}</p>
                </div>
            `;

            navigate('confirmacao');
        }

        // Confirmar agendamento
        async function confirmarAgendamento() {
            try {
                const res = await fetch(`${API_BASE}/api/agendamentos`, {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({
                        barbeiro_id: estadoAgendamento.barbeiro_id,
                        servico_id: estadoAgendamento.servico_id,
                        cliente_nome: estadoAgendamento.cliente_nome,
                        cliente_telefone: estadoAgendamento.cliente_telefone,
                        data_hora: estadoAgendamento.data_hora
                    })
                });

                if (res.ok) {
                    alert('Agendamento confirmado! Voce recebera uma mensagem no WhatsApp.');
                    document.getElementById('agendamento-form').reset();
                    navigate('home');
                } else {
                    alert('Erro ao agendar. Tente novamente.');
                }
            } catch (e) {
                console.error(e);
                alert('Erro ao agendar');
            }
        }

        // Buscar agendamentos
        async function buscarAgendamentos() {
            const tel = document.getElementById('busca-tel').value;
            if (!tel) {
                alert('Digite seu telefone');
                return;
            }

            try {
                const res = await fetch(`${API_BASE}/api/agendamentos?telefone=${encodeURIComponent(tel)}`);
                const agendamentos = await res.json();

                const lista = document.getElementById('lista-agendamentos');
                lista.innerHTML = '';

                if (agendamentos.length === 0) {
                    lista.innerHTML = '<p class="text-gray-600">Nenhum agendamento encontrado</p>';
                    return;
                }

                agendamentos.forEach(a => {
                    const card = document.createElement('div');
                    card.className = 'card p-6 mb-4';
                    const data_hora = new Date(a.data_hora);
                    const data_formatada = data_hora.toLocaleDateString('pt-BR');
                    const hora_formatada = data_hora.toLocaleTimeString('pt-BR', {hour: '2-digit', minute: '2-digit'});

                    card.innerHTML = `
                        <div class="mb-4">
                            <p class="mb-2"><strong>ID:</strong> ${a.id}</p>
                            <p class="mb-2"><strong>Data/Hora:</strong> ${data_formatada} as ${hora_formatada}</p>
                            <p class="mb-2"><strong>Status:</strong> <span class="secondary-text font-semibold">${a.status}</span></p>
                        </div>
                        <button onclick="cancelarAgendamento(${a.id})" class="btn btn-secondary px-4 py-2">
                            Cancelar
                        </button>
                    `;
                    lista.appendChild(card);
                });
            } catch (e) {
                console.error(e);
                alert('Erro ao buscar agendamentos');
            }
        }

        // Cancelar agendamento
        async function cancelarAgendamento(id) {
            if (!confirm('Tem certeza?')) return;

            try {
                const res = await fetch(`${API_BASE}/api/agendamentos/${id}`, {
                    method: 'DELETE'
                });

                if (res.ok) {
                    alert('Agendamento cancelado');
                    buscarAgendamentos();
                } else if (res.status === 403) {
                    alert('Cancelamento nao permitido (menos de 1 hora antes)');
                } else {
                    alert('Erro ao cancelar');
                }
            } catch (e) {
                console.error(e);
                alert('Erro ao cancelar');
            }
        }

        // Init
        window.addEventListener('load', () => {
            loadBarbeiros();
            loadServicos();
            gerarHorarios();
        });
    </script>
</body>
</html>
